// =========================================================
// 🔹 SAFELY Normalize Appsmith Data
// =========================================================
function normalizeData(model) {
  if (!model || !Array.isArray(model.data)) return [];
  return model.data;
}

// =========================================================
// 🔹 Generate Dynamic Column Definitions
// =========================================================
function generateColumns(data) {
  if (!Array.isArray(data) || data.length === 0) return [];
  return Object.keys(data[0]).map(key => ({
    headerName: key.replace(/_/g, " ").replace(/\b\w/g, c => c.toUpperCase()),
    field: key
  }));
}
let gridApi = null;
let gridOptions = null;

// =========================================================
// 🔹 RENDER GRID (Supports Pagination)
// =========================================================
function renderGrid(model) {
  const rowData = normalizeData(model);
  const columnDefs = generateColumns(rowData);
  console.log("[AG] Rendering grid with rows:", rowData.length);
  gridOptions = {
    columnDefs,
    rowData,
    // 🔥 ENABLE PAGINATION
    pagination: true,
    paginationPageSize: 50,
    // Default page size
    paginationPageSizeSelector: true,
    // shows dropdown inside grid

    defaultColDef: {
      sortable: true,
      resizable: true,
      filter: true,
      enableRowGroup: true,
      editable: false,
      menuTabs: ["filterMenuTab"]
    },
    animateRows: true,
    domLayout: "autoHeight",
    popupParent: document.body,
    onGridReady: params => {
      gridApi = params.api;
      console.log("[AG] Grid Ready - Pagination Active");
    }
  };
  const gridDiv = document.querySelector("#myGrid");
  gridDiv.innerHTML = ""; // Clear old grid instance

  gridApi = agGrid.createGrid(gridDiv, gridOptions);
}

// =========================================================
// 🔹 Allow Changing Page Size Dynamically
// =========================================================
function updatePageSize(size) {
  if (gridApi) {
    console.log("[AG] Changing page size to:", size);
    gridApi.paginationSetPageSize(Number(size));
  }
}

// Example dropdown usage:
// <select onchange="updatePageSize(this.value)">
//   <option value="20">20</option>
//   <option value="50" selected>50</option>
//   <option value="100">100</option>
// </select>

// =========================================================
// 🔹 APPSSMITH LIFECYCLE INITIALIZATION
// =========================================================
appsmith.onReady(() => {
  console.log("[Appsmith] App Ready → Initial Grid Render");
  renderGrid(appsmith.model);
  appsmith.onModelChange(newModel => {
    console.log("[Appsmith] Model Updated → Re-render Grid");
    renderGrid(newModel);
  });
});

// =========================================================
// 🔹 ADDITIONAL OPTIONAL HELPERS
// =========================================================
function createRow(index) {
  return {
    id: "D" + (1000 + index),
    value: Math.floor(Math.random() * 1000)
  };
}
function cbFloatingRows() {
  const show = document.getElementById("floating-rows").checked;
  if (show) {
    gridApi.setGridOption("pinnedTopRowData", [createRow(999), createRow(998)]);
    gridApi.setGridOption("pinnedBottomRowData", [createRow(997), createRow(996)]);
  } else {
    gridApi.setGridOption("pinnedTopRowData", undefined);
    gridApi.setGridOption("pinnedBottomRowData", undefined);
  }
}
function setAutoHeight() {
  gridApi.setGridOption("domLayout", "autoHeight");
  document.querySelector("#myGrid").style.height = "";
}
function setFixedHeight() {
  gridApi.setGridOption("domLayout", "normal");
  document.querySelector("#myGrid").style.height = "400px";
}

